        log("\n[EXTRACT 1] Accuracy model (Ch5 5.5.1)")
        accuracy_result = extract_interaction_from_text(CH5_SUMMARY, 'accuracy')

        if accuracy_result is None:
            raise ValueError("Failed to extract accuracy interaction from Ch5 5.5.1 summary")

