        log(f"  Confidence: beta={confidence_result['beta']:.4f}, p={confidence_result['p_value']:.4f}")

        # =========================================================================
        # VALIDATE CONFIDENCE P-VALUE
        # =========================================================================
        log("\n[VALIDATE] Checking confidence p-value ~0.553")
        conf_p = confidence_result['p_value']
        if 0.50 <= conf_p <= 0.60:
            log(f"[PASS] Confidence p-value ({conf_p:.3f}) in expected range [0.50, 0.60]")
        else:
            log(f"[WARN] Confidence p-value ({conf_p:.3f}) outside expected range [0.50, 0.60]")

        # =========================================================================
        # VALIDATE NUMERIC RANGES
        # =========================================================================
        log("\n[VALIDATE] Numeric range checks")

        # Check beta range
        result = validate_numeric_range(df_interactions['beta'].values, -10, 10, 'beta')
